function initTimeline(){function e(){const e=window.scrollY,n=window.innerHeight;t.forEach(t=>{const i=t.offsetTop,o=t.offsetHeight,c=i+o/2,s=e+n/2,l=Math.abs(s-c);l<n/2?t.classList.add("active"):t.classList.remove("active")}),e>100&&i?i.style.opacity="0":i&&(i.style.opacity="1")}const t=document.querySelectorAll(".history-timeline-item"),i=document.querySelector(".history-scroll-indicator");window.addEventListener("scroll",e),e()}document.getElementById("history-year").textContent=(new Date).getFullYear(),document.addEventListener("DOMContentLoaded",initTimeline);